#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int firstRow[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &firstRow[i]);
    }
    int secondRow[N];
    for (int i = 0; i < N; i++) {
        secondRow[i] = i + 1;
    }
    for (int i = 0; i < N; i++) {
        int maxSum = 0;
        for (int j = 0; j < N; j++) {
            int sum = firstRow[j] + secondRow[(j + i) % N];
            if (sum > maxSum) {
                maxSum = sum;
            }
        }
        printf("%d ", maxSum);
    }
    return 0;
}

