const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const N = parseInt(readline());
const firstRow = readline().split(' ').map(Number);
const secondRow = Array.from({ length: N }, (_, i) => i + 1);
for (let i = 0; i < N; i++) {
    let maxSum = 0;
    for (let j = 0; j < N; j++) {
        const sum = firstRow[j] + secondRow[(j + i) % N];
        if (sum > maxSum) {
            maxSum = sum;
        }
    }
    process.stdout.write(maxSum + ' ');
}
